return items.map(item => {
  const d = item.json;
  const errors   = [];
  const warnings = [];

  const margen         = d.margen         ?? null;
  const beneficioPct   = d.beneficioPct   ?? 0;
  const tipo           = d.tipo           || 'ninguno';
  const riesgo         = d.riesgo         || 'alto';
  const confianza      = d.confianza      ?? 0;
  const best           = d.best           || {};
  const casasDistintas = d.casasDistintas ?? 0;

  // ── Errores graves ───────────────────────────────────────────

  // 1. LLM dice surebet pero margen >= 1
  if (tipo === 'surebet' && margen !== null && margen >= 1) {
    errors.push(`MATH_ERROR: tipo='surebet' pero margen=${margen.toFixed(4)}`);
  }

  // 2. LLM dice surebet pero casas insuficientes
  if (tipo === 'surebet' && casasDistintas < 3) {
    errors.push(`HOUSES_ERROR: tipo='surebet' pero casasDistintas=${casasDistintas} (necesita 3)`);
  }

  // 3. LLM dice ninguno pero hay surebet matemática real con 3 casas
  if (tipo === 'ninguno' && margen !== null && margen < 1 && casasDistintas === 3) {
    errors.push(`MISSED_SUREBET: margen=${margen.toFixed(4)} < 1 con 3 casas pero LLM='ninguno'`);
  }

  // 4. Confianza 0 con datos completos
  const hasOdds = best?.home?.odds && best?.draw?.odds && best?.away?.odds;
  if (confianza === 0 && hasOdds) {
    errors.push(`FALLBACK_ERROR: confianza=0 con datos completos`);
  }

  // 5. Riesgo bajo con beneficioPct bajo
  if (riesgo === 'bajo' && beneficioPct < 0.5) {
    errors.push(`RISK_ERROR: riesgo='bajo' pero beneficioPct=${beneficioPct.toFixed(3)}%`);
  }

  // ── Warnings ────────────────────────────────────────────────

  if (tipo === 'surebet' && confianza < 40) {
    warnings.push(`LOW_CONFIDENCE: surebet real pero confianza=${confianza}`);
  }
  if (tipo === 'ninguno' && confianza > 80) {
    warnings.push(`HIGH_CONFIDENCE_NINGUNO: confianza=${confianza} con tipo='ninguno'`);
  }
  if (beneficioPct > 0 && tipo !== 'surebet') {
    warnings.push(`TYPE_MISMATCH: beneficioPct=${beneficioPct.toFixed(3)}% > 0 pero tipo='${tipo}'`);
  }

  // ── Auto-corrección ──────────────────────────────────────────
  const llmValid = errors.length === 0;
  const llmScore = llmValid ? (warnings.length === 0 ? 'OK' : 'WARNING') : 'ERROR';

  let tipoFinal       = tipo;
  let riesgoFinal     = riesgo;
  let confianzaFinal  = confianza;
  let comentarioFinal = d.comentario || '';

  if (!llmValid) {
    // Prioridad 1: surebet matemática real — anula cualquier clasificación LLM
    if (margen !== null && margen < 1) {
      tipoFinal       = 'surebet';
      riesgoFinal     = beneficioPct > 2.0 ? 'bajo' : beneficioPct > 0.5 ? 'medio' : 'alto';
      confianzaFinal  = beneficioPct > 1.5 ? 85 : beneficioPct > 0.5 ? 65 : 45;
      comentarioFinal = `[Auto-corregido] Surebet real: margen=${margen.toFixed(4)}, beneficio=${beneficioPct.toFixed(2)}%`;
    } else if (errors.some(e => e.startsWith('HOUSES_ERROR'))) {
      // Margen < 1 pero casas insuficientes — degradar a ninguno
      tipoFinal       = 'ninguno';
      confianzaFinal  = 10;
      comentarioFinal = `[Auto-corregido] Margen positivo pero solo ${casasDistintas} casa(s) distinta(s)`;
    } else if (confianza === 0 && hasOdds) {
      // Prioridad 3: fallback — datos completos pero LLM devolvió confianza=0
      confianzaFinal  = 10;
      comentarioFinal = `[Auto-corregido] Datos completos, sin oportunidad clara`;
    }
  }

  return {
    json: {
      ...d,
      tipo:       tipoFinal,
      riesgo:     riesgoFinal,
      confianza:  confianzaFinal,
      comentario: comentarioFinal,
      llmValid,
      llmScore,
      llmErrors:   errors,
      llmWarnings: warnings
    }
  };
});

const cfg = $('CONFIG').first().json;

let allowedLeagues = [];
try {
  allowedLeagues = JSON.parse(cfg.CFG_LEAGUES || '[]');
} catch(e) {
  allowedLeagues = (cfg.CFG_LEAGUES || '')
    .split(',')
    .map(l => l.trim())
    .filter(Boolean);
}

const normalize = str => str
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .trim();

// Marcadores de competencia femenina — se excluyen siempre
// independientemente de CFG_LEAGUES
const femeninoMarkers = [
  'women', 'femenino', 'femenina', 'femeni', 'feminine',
  'ladies', 'mujer', 'mujeres', 'female', '(f)', 'woman',
  'frauen',       // alemán
  'femminile',    // italiano
  'feminino',     // portugués
  'feminina',     // portugués
  'feminin',      // francés/rumano
  'dames',        // francés/holandés
  'naiset',       // finlandés
  'kvinder',      // danés
  'damer'         // noruego/sueco
];

const isFemenino = (league) => {
  const norm = normalize(league);
  return femeninoMarkers.some(m => norm.includes(m));
};

const raw    = items[0].json;
const events = raw.events || [];

// Si lista vacía: pasan todos (excepto femeninos siempre)
const sinFiltroLiga = allowedLeagues.length === 0;
const allowedNorm   = allowedLeagues.map(normalize);

const filtered = events.filter(e => {
  const league     = e.league || e.league_raw || '';
  const leagueNorm = normalize(league);

  // Excluir femeninos siempre, sin excepción
  if (isFemenino(league)) return false;

  // Sin filtro de liga configurado: pasa todo lo masculino
  if (sinFiltroLiga) return true;

  // Coincidencia parcial con ligas permitidas
  return allowedNorm.some(allowed =>
    leagueNorm.includes(allowed) || allowed.includes(leagueNorm)
  );
});

const skipped     = events.length - filtered.length;
const femeninos   = events.filter(e => isFemenino(e.league || '')).length;
const fueraLiga   = skipped - femeninos;

console.log(`Filter - ByLeague: ${filtered.length} OK | ${femeninos} femeninos excluidos | ${fueraLiga} fuera de liga`);
console.log('Ligas permitidas:', allowedLeagues);
console.log('Ligas encontradas:', [...new Set(events.map(e => e.league))]);

if (filtered.length === 0) {
  return [{ json: { events: [], _filteredCount: 0, _totalCount: events.length, _femeninosExcluidos: femeninos } }];
}

return [{ json: {
  ...raw,
  events: filtered,
  _filteredCount:       filtered.length,
  _totalCount:          events.length,
  _femeninosExcluidos:  femeninos,
  _fueraLigaExcluidos:  fueraLiga
}}];

