parameters.jsCode:
const src = $('Loop Over Items').item.json;

const match          = src.match          || '';
const league         = src.league         || '';
const country        = src.country        || '';
const margen         = src.margen         ?? null;
const beneficioPct   = src.beneficioPct   ?? 0;
const surebet        = src.surebet        ?? false;
const casasDistintas = src.casasDistintas ?? 0;
const best           = src.best           || {};

// Solo datos matemáticos relevantes para el clasificador
const normalized = {
  match, league, country,
  margen, beneficioPct, surebet, casasDistintas,
  best: {
    home: { odds: best?.home?.odds ?? null, bookmaker: best?.home?.bookmaker ?? null },
    draw: { odds: best?.draw?.odds ?? null, bookmaker: best?.draw?.bookmaker ?? null },
    away: { odds: best?.away?.odds ?? null, bookmaker: best?.away?.bookmaker ?? null }
  }
};

const hasOdds = normalized.best.home.odds
  && normalized.best.draw.odds
  && normalized.best.away.odds;

return [{
  json: {
    ...src,
    normalized,
    payloadString: JSON.stringify(normalized),
    skipLLM: !hasOdds
  }
}];

// AttachLastHash: fusiona datos de Baserow con el item del Loop
// Detecta si Baserow devolvió una fila existente o está vacío
return items.map(it => {
  const out = { ...it.json };

  const norm = v => {
    if (v === null || v === undefined) return null;
    const s = String(v).trim();
    return (s === '' || s.toLowerCase() === 'null') ? null : s.toLowerCase();
  };

  // El item del Loop tiene el hash calculado
  // El item de Baserow (si existe) tiene 'id' y los campos de la tabla
  const loopItem = $('Loop Over Items').item.json;

  // Recuperar hash calculado desde el Loop
  out.hash = norm(loopItem.hash) || null;

  // Detectar si Baserow devolvió una fila real
  // Una fila de Baserow siempre tiene campo 'id' (número entero)
  const baserowId = out.id ?? null;
  out.baserowRowExists = (baserowId !== null && baserowId !== undefined && baserowId !== '');
  out.baserowRowId = out.baserowRowExists ? baserowId : null;

  // Hash guardado en Baserow (campo que hayas definido)
  const possibleHashKeys = ['Hash', 'hash', 'lastHash', 'last_hash'];
  let savedHash = null;
  for (const k of possibleHashKeys) {
    if (out[k] !== undefined && out[k] !== null && out[k] !== '') {
      savedHash = norm(out[k]);
      break;
    }
  }
  out.lastHash = savedHash;

  // beneficioPct desde Loop (ya calculado en SurebetCalc)
  out.beneficioPct = loopItem.beneficioPct ?? 0;

  return { json: out };
});

// Hash robusto con crypto nativo de Node.js
const crypto = require('crypto');

return items.map(item => {
  const { match, best } = item.json;
  const raw = `${match}-${best?.home?.odds}-${best?.draw?.odds}-${best?.away?.odds}`;
  const hash = crypto.createHash('md5').update(raw).digest('hex');
  return { json: { ...item.json, hash } };
});

const parseOdd = (v) => {
  if (v === null || v === undefined) return NaN;
  if (typeof v === 'number') return v;
  let s = String(v).trim().replace(',', '.');
  if (/^\d+\/\d+$/.test(s)) {
    const [a, b] = s.split('/').map(Number);
    if (b === 0) return NaN;
    return 1 + (a / b);
  }
  if (/^[+-]\d+$/.test(s)) {
    const n = Number(s);
    if (n > 0) return 1 + (n / 100);
    if (n < 0) return 1 + (100 / Math.abs(n));
  }
  if (s.endsWith('%')) {
    const p = parseFloat(s.slice(0, -1));
    if (!isFinite(p) || p <= 0) return NaN;
    return 100 / p;
  }
  const num = Number(s);
  if (isFinite(num)) {
    if (num > 0 && num < 1) return 1 / num;
    return num;
  }
  return NaN;
};

const round = (n, d = 3) => Math.round(n * Math.pow(10, d)) / Math.pow(10, d);

// Redondear al entero más cercano (sin decimales, sin riesgo matemático)
const roundToInt = (n) => Math.round(n);

const CAPITAL_TOTAL = Number($('CONFIG').first().json.CFG_CAPITAL ?? 100);

return items.map(item => {
  const { match, best, league, country, region, timestamp } = item.json || {};

  if (!best) {
    return { json: { match, error: 'best missing', raw: item.json } };
  }

  const cuotaHome = parseOdd(best?.home?.odds ?? null);
  const cuotaDraw = parseOdd(best?.draw?.odds ?? null);
  const cuotaAway = parseOdd(best?.away?.odds ?? null);

  const invalid = [cuotaHome, cuotaDraw, cuotaAway].some(v => !isFinite(v) || v <= 0);
  if (invalid) {
    return {
      json: {
        match, best, league, country, region, timestamp,
        cuotaHome, cuotaDraw, cuotaAway,
        margen: null, surebet: false,
        beneficioPct: 0, stakes: null,
        gananciaEsperada: 0,
        capitalTotal: CAPITAL_TOTAL,
        casasDistintas: 0,
        debug: 'Cuotas inválidas o no convertibles'
      }
    };
  }

  // Validar casas distintas — mínimo 2 para arbitraje real
  const casas = new Set([
    best?.home?.bookmaker,
    best?.draw?.bookmaker,
    best?.away?.bookmaker
  ].filter(Boolean));
  const casasDistintas = casas.size;

  const invHome = 1 / cuotaHome;
  const invDraw = 1 / cuotaDraw;
  const invAway = 1 / cuotaAway;
  const margen  = invHome + invDraw + invAway;

  const surebetMatematica = margen < 1;
  const surebet           = surebetMatematica && casasDistintas === 3;
  const beneficioPct      = surebet ? (1 - margen) * 100 : 0;

  const denom = invHome + invDraw + invAway;
  const stakeHomeExacto = (CAPITAL_TOTAL * invHome) / denom;
  const stakeDrawExacto = (CAPITAL_TOTAL * invDraw) / denom;
  const stakeAwayExacto = (CAPITAL_TOTAL * invAway) / denom;

  // Redondeo a entero — seguro para cualquier capital
  const stakeHome = roundToInt(stakeHomeExacto);
  const stakeDraw = roundToInt(stakeDrawExacto);
  const stakeAway = roundToInt(stakeAwayExacto);

  // Ganancia esperada en soles con stakes redondeados
  // = lo que cobras en el outcome ganador - capital total apostado
  const capitalApostado   = stakeHome + stakeDraw + stakeAway;
  const retornoHome       = stakeHome * cuotaHome;
  const retornoDraw       = stakeDraw * cuotaDraw;
  const retornoAway       = stakeAway * cuotaAway;
  // Ganancia mínima garantizada (el peor retorno menos lo apostado)
  const gananciaEsperada  = round(
    Math.min(retornoHome, retornoDraw, retornoAway) - capitalApostado, 2
  );

  return {
    json: {
      match, best, league, country, region, timestamp,
      cuotaHome: round(cuotaHome, 3),
      cuotaDraw: round(cuotaDraw, 3),
      cuotaAway: round(cuotaAway, 3),
      margen: round(margen, 6),
      surebet,
      surebetMatematica,
      casasDistintas,
      beneficioPct:    round(beneficioPct, 3),
      gananciaEsperada,
      capitalApostado,
      stakes: {
        home: stakeHome,
        draw: stakeDraw,
        away: stakeAway
      },
      stakesExactos: {
        home: round(stakeHomeExacto, 2),
        draw: round(stakeDrawExacto, 2),
        away: round(stakeAwayExacto, 2)
      },
      capitalTotal: CAPITAL_TOTAL,
      currencies: {
        home: best.home?.currency || 'PEN',
        draw: best.draw?.currency || 'PEN',
        away: best.away?.currency || 'PEN'
      }
    }
  };
});

return items.map(item => {
  const { match, offers, league, country, region, timestamp } = item.json || {};
  const best = { home: null, draw: null, away: null };

  (offers || []).forEach(o => {
    const { bookmaker, odds, currency, url } = o;
    if (!best.home || odds.home > best.home.odds)
      best.home = { bookmaker, odds: odds.home, currency, url };
    if (!best.draw || odds.draw > best.draw.odds)
      best.draw = { bookmaker, odds: odds.draw, currency, url };
    if (!best.away || odds.away > best.away.odds)
      best.away = { bookmaker, odds: odds.away, currency, url };
  });

  return { json: { match, best, league, country, region, timestamp } };
});

const arr = items.map(i => i.json);
const grouped = {};
arr.forEach(r => {
  if (!grouped[r.match]) grouped[r.match] = [];
  grouped[r.match].push(r);
});
return Object.keys(grouped).map(m => ({
  json: {
    match: m,
    offers: grouped[m],
    // Preservar metadata del primer item del grupo
    league: grouped[m][0]?.league || null,
    country: grouped[m][0]?.country || null,
    region: grouped[m][0]?.region || null,
    timestamp: grouped[m][0]?.timestamp || null
  }
}));

// Normalizar eventos desde la API
// Ampliar currencyMap para soportar múltiples regiones
const raw = items[0].json;
const events = raw.events || [];

const currencyMap = {
  // South America
  'Peru': 'PEN', 'Brazil': 'BRL', 'Argentina': 'ARS',
  'Chile': 'CLP', 'Colombia': 'COP', 'Uruguay': 'UYU',
  'South America': 'PEN',
  // Europe
  'England': 'GBP', 'Spain': 'EUR', 'Germany': 'EUR',
  'Italy': 'EUR', 'France': 'EUR', 'Netherlands': 'EUR',
  'Portugal': 'EUR', 'Europe': 'EUR',
  // North America
  'United States': 'USD', 'Mexico': 'MXN', 'Canada': 'CAD',
  'North America': 'USD',
  // Asia
  'Japan': 'JPY', 'China': 'CNY', 'South Korea': 'KRW',
  // Default
  'default': 'USD'
};

const normalized = events.flatMap(e => {
  const match = `${e.homeTeam} vs ${e.awayTeam}`;
  const timestamp = e.timestamp;
  const bookmakers = e.canonical?.bookmakers || {};

  return Object.keys(bookmakers).flatMap(bk => {
    const odds = bookmakers[bk].odds || {};
    const oneXtwo = odds['1X2'] || odds['1x2'] || null;
    if (!oneXtwo) return [];

    const currency = bookmakers[bk].currency
      || currencyMap[e.country]
      || currencyMap['default'];

    return [{
      match,
      timestamp,
      league: e.league || null,
      country: e.country || null,
      region: e.region || null,
      bookmaker: bk,
      market: '1X2',
      odds: { home: oneXtwo[0], draw: oneXtwo[1], away: oneXtwo[2] },
      url: bookmakers[bk].url || null,
      currency
    }];
  });
});

return normalized.map(r => ({ json: r }));

const cfg = $('CONFIG').first().json;
const horaInicio = cfg.CFG_HORA_INICIO ?? 8;
const horaFin = cfg.CFG_HORA_FIN ?? 23;

const hour = Number(
  new Date().toLocaleString('en-US', {
    hour: 'numeric',
    hour12: false,
    timeZone: 'America/Lima'
  })
);

return [
  {
    json: {
      ...cfg,
      horaPeru: hour,
      dentroHorario: (hour >= horaInicio && hour < horaFin)
    }
  }
];
